     */
    public static int maxLenSub(List<Integer> arr, int n) {

solution:
        int[] mls = new int[n];
        int max = 0;

        // mls[i] => max difference between arr[i] and arr[i-1]

        for (int i = 0; i < n; i++) {
            mls[i] = 1;
            for (int j = i - 1; j >= 0; j--) {
                if (Math.abs(arr.get(i) - arr.get(j)) <= 1 && mls[i] < mls[j] + 1) {
                    mls[i] = mls[j] + 1;
                }
            }
            if (max < mls[i]) {
                max = mls[i];
            }
        }

        return max;
    }
}

