     * 6
     * > countSubstrings("1101112", 7)
     * 12
     */
    public static int countSubstrings(String s, int n) {

solution:
        int count = 0;
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j <= n; j++) {
