                int diff = o1.get(o1.size() - 1).hashCode() - o2.get(o2.size() - 1).hashCode();
                if (diff == 0) {
                    diff = o1.get(0).hashCode() - o2.get(0).hashCode();
                }
                return diff;
            }
        });
        return list;
    }
