public class BellNumber {
    public static BigInteger bellNumber(int n) {
        if (n == 0) {
            return BigInteger.ONE;
        }
        BigInteger result = BigInteger.ZERO;
        for (int i = 0; i <= n; i++) {
            result = result.add(bellNumber(i).multiply(bellNumber(n - i)));
        }
        return result;
    }
}

