     */
    public static List<Integer> maxOccurrences(List<Integer> nums) {

solution:
        int max = 0, max_occ = 0;
        HashMap<Integer, Integer> occ = new HashMap<>();
        for (int i : nums) {
            if (occ.containsKey(i)) {
                occ.put(i, occ.get(i) + 1);
            } else {
                occ.put(i, 1);
            }
            if (occ.get(i) > max_occ) {
                max_occ = occ.get(i);
                max = i;
            }
        }
        List<Integer> result = new ArrayList<>();
        result.add(max);
        result.add(max_occ);
        return result;
    }
}

